const r=new Set(["gpt","glm","swe","oss"]);function u(s){if(!s)return!1;let t=!1;for(const e of s){if(e>="0"&&e<="9"){t=!0;continue}if(!(e==="."||e==="b"||e==="B"||e==="m"||e==="M"||e==="k"||e==="K"))return!1}return t}function o(s){if(!s)return!1;for(const t of s)if(t<"0"||t>"9")return!1;return!0}function f(s){if(!s)return"";const t=s.split("-"),e=[];for(let i=0;i<t.length;i++){const n=t[i];if(n){if(r.has(n.toLowerCase())){e.push(n.toUpperCase());continue}if(o(n)&&i+1<t.length&&o(t[i+1])){e.push(`${n}.${t[i+1]}`),i++;continue}if(u(n)){e.push(n);continue}e.push(n[0].toUpperCase()+n.slice(1))}}return e.join(" ")}export{f as d};
